import React from 'react';
import { resolveUrl } from '../utils';
import { Dialog } from 'primereact/dialog';
import { Rating } from 'primereact/rating';
import { Button } from 'primereact/button';

function ItemDetailDialog({ item, visible, onHide, onDelete, isOwner, onReserve, onUnreserve }) {
  if (!item) return null;

  const headerTemplate = () => {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%' }}>
        <span style={{ fontSize: '20px', fontWeight: 600 }}>Детали подарка</span>
        {isOwner && onDelete && (
          <Button
            icon="pi pi-trash"
            className="p-button-rounded p-button-text p-button-danger"
            onClick={() => { onDelete(item.id); onHide(); }}
            tooltip="Удалить подарок"
            tooltipOptions={{ position: 'bottom' }}
            style={{ marginRight: '8px' }}
          />
        )}
      </div>
    );
  };

  return (
    <Dialog
      visible={visible}
      onHide={onHide}
      className="item-detail-dialog"
      header={headerTemplate()}
      closable
      headerStyle={{ padding: '1.5rem', borderBottom: '1px solid #e0e0e0' }}
      contentStyle={{ padding: '1.5rem' }}
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        {/* Изображение */}
        <div style={{ 
          width: '100%', 
          height: '300px', 
          background: '#f5f5f5',
          borderRadius: '12px',
          overflow: 'hidden',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}>
          {item.imageUrl ? (
            <img
              src={resolveUrl(item.imageUrl)}
              alt={item.title}
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'contain'
              }}
            />
          ) : (
            <i className="pi pi-image" style={{ fontSize: '4rem', color: '#ccc' }}></i>
          )}
        </div>

        {/* Название и рейтинг */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <h2 style={{ margin: 0, fontSize: '24px', fontWeight: 600, color: '#000' }}>
            {item.title}
          </h2>
          {item.reservedByMe && (
            <div style={{
              width: '40px',
              height: '40px',
              borderRadius: '50%',
              background: '#e91e63',
              color: 'white',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '18px',
              fontWeight: 600
            }}>
              B
            </div>
          )}
        </div>

        {/* Рейтинг */}
        {item.priority && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Rating value={item.priority} readOnly cancel={false} onIcon={<img src="/images/path-2.svg" alt="heart" width="20px" height="20px" />} offIcon={<img src="/images/ti-heart.svg" alt="heart" width="20px" height="20px" />} />
          </div>
        )}

        {/* Цена и ссылка */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          {item.price && (
            <div style={{ fontSize: '24px', fontWeight: 600, color: '#000' }}>
              {item.price} ₽
            </div>
          )}
          {item.url && (
            <a
              href={item.url}
              target="_blank"
              rel="noopener noreferrer"
              style={{ 
                color: '#188700', 
                textDecoration: 'none',
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
                fontSize: '16px',
                fontWeight: 500
              }}
            >
              Ссылка <i className="pi pi-external-link"></i>
            </a>
          )}
        </div>

        {/* Комментарий */}
        {item.description && (
          <div>
            <div style={{ 
              fontSize: '14px', 
              color: '#999', 
              marginBottom: '8px',
              fontWeight: 500
            }}>
              Комментарий
            </div>
            <div style={{ 
              fontSize: '14px', 
              color: '#666',
              lineHeight: '1.6'
            }}>
              {item.description}
            </div>
          </div>
        )}

        {/* Кнопка бронирования для не-владельца */}
        {!isOwner && (
          <div style={{ marginTop: '1rem' }}>
            {/* Приватность бронирования */}
            <div style={{ marginBottom: '1rem' }}>
              <div style={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '8px',
                marginBottom: '8px',
                fontSize: '14px',
                fontWeight: '500',
                color: '#1e293b'
              }}>
                <span>Приватность бронирования подарка</span>
                <i className="pi pi-gift" style={{ fontSize: '16px', color: '#188700' }}></i>
              </div>
              
              <div style={{
                width: '100%',
                padding: '12px 16px',
                borderRadius: '8px',
                border: '2px solid #188700',
                fontSize: '14px',
                color: '#64748b',
                backgroundColor: 'white',
                cursor: 'pointer',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '8px'
              }}>
                <span>Не выбрана</span>
                <i className="pi pi-chevron-up" style={{ fontSize: '12px', color: '#1e293b' }}></i>
              </div>
              
              <p style={{ 
                fontSize: '12px', 
                color: '#64748b', 
                margin: 0,
                lineHeight: '1.4'
              }}>
                Хотите подписаться своим именем или остаться анонимным?
              </p>
            </div>

            {item.reservedByMe ? (
              <button
                onClick={() => { onUnreserve(item); onHide(); }}
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: 'white',
                  color: '#188700',
                  border: '2px solid #188700',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  transition: 'all 0.2s'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = '#F0FDF4';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = 'white';
                }}
              >
                <i className="pi pi-times" style={{ fontSize: '18px' }}></i>
                Отменить бронь
              </button>
            ) : !item.isReserved ? (
              <button
                onClick={() => { onReserve(item); onHide(); }}
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: '#188700',
                  color: 'white',
                  border: 'none',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  transition: 'background 0.2s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.background = '#146600'}
                onMouseLeave={(e) => e.currentTarget.style.background = '#188700'}
              >
                <i className="pi pi-gift" style={{ fontSize: '18px' }}></i>
                Забронировать
              </button>
            ) : (
              <button
                disabled
                style={{
                  width: '100%',
                  height: '45px',
                  borderRadius: '8px',
                  background: '#cccccc',
                  color: '#666666',
                  border: 'none',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: 'not-allowed',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px'
                }}
              >
                <i className="pi pi-lock" style={{ fontSize: '18px' }}></i>
                Забронировано
              </button>
            )}
          </div>
        )}
      </div>
    </Dialog>
  );
}

export default ItemDetailDialog;
